translatedPrompt:
{
  "type": "显示 Google Maps Street View 界面的电脑显示器照片",
  "scene": {
    "environment": "{argument name=\"environment\" default=\"晴朗蓝天下的荒凉沙漠景观\"}",
    "subject": "{argument name=\"subject\" default=\"巨大的古老石墙，带有完美契合的巨石砌筑，阻挡在土路上，中心处开有一个矩形门洞\"}",
    "foreground": "投射在土路上的 Google Street View 车辆阴影，车顶装有 360 度全景摄像头"
  },
  "ui_elements": {
    "browser_bar": "顶部的 URL 栏显示 google.com/maps 以及经纬度坐标",
    "top_left_panel": "黑色半透明信息框，显示文本“Unnamed Road”、“{argument name=\"region\" default=\"阿塔卡马地区\"}”以及“Street View - 2022 年 9 月”",
    "bottom_left_panel": "带有黄色 Pegman 图标的迷你地图插图",
    "bottom_right_panel": "显示蓝色路线、Pegman、缩放控件以及文本“{argument name=\"distance text\" default=\"距最近城镇 340 公里\"}”的迷你地图插图",
    "bottom_bar": "底部中央的 Google Logo、右侧的指南针图标，以及沿底部的版权/拍摄日期文本"
  },
  "style_details": "可见的屏幕反光和轻微的显示器畸变，以模拟用智能手机拍摄物理屏幕的效果"
}
